CustomField.formula:
IF(
Account__r.IsPersonAccount,
/* If Primary Account is a Person */
TEXT(Account__r.Salutation) + " " + Account__r.FirstName + " " + Account__r.LastName
+ " is " +
IF(
Related_Account__r.IsPersonAccount,
/* If Related Account is a Person */
TEXT(Related_Account__r.Salutation) + " " + Related_Account__r.FirstName + " " + Related_Account__r.LastName,
Related_Account__r.Name
)
+ "'s " +
/* Use the reciprocal relationship type if it exists, otherwise use this record's type */
IF(
ISBLANK(Reciprocal_Relationship__c),
TEXT(Relationship__c),
TEXT(Reciprocal_Relationship__r.Relationship__c)
),

/* If Related Account is a Business */
Related_Account__r.Name + " is " +
IF(
Account__r.IsPersonAccount,
/* If Primary Account is a Person */
TEXT(Account__r.Salutation) + " " + Account__r.FirstName + " " + Account__r.LastName,
Account__r.Name
)
+ "'s " +
/* Use the reciprocal relationship type if it exists, otherwise use this record's type */
IF(
ISBLANK(Reciprocal_Relationship__c),
TEXT(Relationship__c),
TEXT(Reciprocal_Relationship__r.Relationship__c)
)

)
